const b = $input.first().json.body || {};
const esc = v => (v || '').toString().replace(/'/g, "''");

const storeCode     = esc(b.storeCode);
const empCode       = esc(b.employeeCode);
const empName       = esc(b.employeeName);
const empMobile     = esc(b.contactNumber);
const empDesig      = esc(b.designation || '');
const storeCity     = esc(b.city);
const storeRegion   = esc(b.region);
const stateName     = esc(b.state);
const storeName     = esc(b.storeName);
const storeEmail    = esc(b.storeEmail || '');
const managerName   = esc(b.managerName || '');
const managerMobile = esc(b.managerMobile || '');
const asmName       = esc(b.asmName || '');
const asmMobile     = esc(b.asmMobile || '');
const fmName        = esc(b.fmName || '');
const fmEmail       = esc(b.fmEmail || '');
const fmMobile      = esc(b.fmMobile || '');
const productName   = esc(b.productName);
const productType   = esc(b.productType || '');
const vendorName    = esc(b.vendorName);
const contractType  = esc(b.contractType || '');
const productLoc    = esc(b.productLocation);
const nature        = esc(b.natureOfComplaint);
const type          = esc(b.complaintType);
const tat           = parseInt(b.tatDays || 0);
const uid           = parseInt(b.uid || 1);
const source        = esc(b.source || 'Manual');
const emailSubject  = esc(b.emailSubject || '');
const callTxnId     = esc(b.callTxnId || '');
const emailMsgId    = esc(b.emailMessageId || '');
const emailFrom     = esc(b.emailFrom || '');
const emailTo       = esc(b.emailTo || '');
const remarks       = esc(b.remarks || 'Complaint logged');

const attachmentLinks = Array.isArray(b.attachmentLinks) ? b.attachmentLinks : [];
const attachmentText  = attachmentLinks.length
  ? '\n\nAttachments:\n' + attachmentLinks.map(a => `- ${a.name}: ${a.viewLink}`).join('\n')
  : '';

const edc = new Date();
edc.setDate(edc.getDate() + tat);
const edcStr = edc.toISOString().split('T')[0];

const txnId = callTxnId || emailMsgId;

const insertStore = `INSERT INTO vmm_complaintstores (empid, empcode, empname, sourceofcomplaints, empmobileno, empdesignation, storeid, storecode, storename, storeemail, storecity, storeregion, statename, managername, managermobileno, asmname, asmmobileno, fmid, fmname, fmemail, fmmobileno, sourceofctxnid, sourceofcsubject, uid, created, updated, is_deleted) VALUES (0, '${empCode}', '${empName}', '${source}', '${empMobile}', '${empDesig}', 0, '${storeCode}', '${storeName}', '${storeEmail}', '${storeCity}', '${storeRegion}', '${stateName}', '${managerName}', '${managerMobile}', '${asmName}', '${asmMobile}', 0, '${fmName}', '${fmEmail}', '${fmMobile}', '${txnId}', '${emailSubject}', ${uid}, NOW(), NOW(), 'No')`;

return [{ json: {
  insertStore,
  storeCode: b.storeCode || '',
  empCode: b.employeeCode || '',
  productName, productType, vendorName, contractType, productLoc, nature, type, tat, uid, edcStr,
  storeEmail: b.storeEmail || '',
  storeName: b.storeName || '',
  empName: b.employeeName || '',
  source, emailSubject, emailFrom, emailTo,
  remarks: remarks + attachmentText
} }];

const prev       = $('Prepare Data').first().json;
const storeRow   = $input.first().json;
const storeRefId = storeRow.id || 0;
const esc = v => (v || '').toString().replace(/'/g, "''");

const insertComplaint = `INSERT INTO vmm_complaints (storerefid, productname, producttype, vendorname, contract_type, productlocation, natureofproblem, typeofcomplaint, tat, productid, vendorid, uid, created, updated, is_deleted) VALUES (${storeRefId}, '${esc(prev.productName)}', '${esc(prev.productType)}', '${esc(prev.vendorName)}', '${esc(prev.contractType)}', '${esc(prev.productLoc)}', '${esc(prev.nature)}', '${esc(prev.type)}', ${prev.tat}, 0, 0, ${prev.uid}, NOW(), NOW(), 'No')`;

return [{ json: { insertComplaint, storeRefId, prev } }];

const prev        = $('Build Complaint INSERT').first().json;
const complaintId = $('Get Complaint ID').first().json.id || 0;
const lastno      = $input.first().json.lastno || 0;

const now = new Date();
const yy  = String(now.getFullYear()).slice(-2);
const mm  = String(now.getMonth() + 1).padStart(2, '0');
const dd  = String(now.getDate()).padStart(2, '0');
const complaintno = yy + mm + dd + String(lastno);

const esc = v => (v || '').toString().replace(/'/g, "''");
const p = prev.prev;

const sourceLines = [
  `Source: ${p.source || 'Manual'}`,
  p.emailSubject ? `Email Subject: ${p.emailSubject}` : '',
  p.emailFrom    ? `From: ${p.emailFrom}` : '',
  p.emailTo      ? `To: ${p.emailTo}` : '',
  '',
  p.remarks || 'Complaint logged'
].filter(Boolean).join('\n');

const updateNo  = `UPDATE vmm_complaints SET complaintno = '${complaintno}' WHERE id = ${complaintId}`;
const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, created, is_deleted) VALUES (${complaintId}, '${esc(sourceLines)}', 'Logged', ${p.uid}, NOW(), 'No')`;

return [{ json: { complaintId, complaintno, updateNo, insertLog, p } }];

const d   = $('Generate Complaint No').first().json;
const p   = d.p;
const esc = v => (v || '').toString().replace(/'/g, "''");

const insertEsc = `INSERT INTO vmm_vendorescalations (complaintid, ticketno, escalationlevel, closuredate, uid, created, is_deleted) VALUES (${d.complaintId}, '', 1, '${p.edcStr}', ${p.uid}, NOW(), 'No')`;

return [{ json: { insertEsc, complaintId: d.complaintId, complaintno: d.complaintno, p } }];
